@@ -1143,6 +1143,15 @@ Value *InstCombinerImpl::SimplifySelectsFeedingBinaryOp(BinaryOperator &I,
       else if (True && !False)
         False = Builder.CreateBinOp(Opcode, C, F);
     }
+    // (A ? B : C) op (A ? C : B) -> B op C (for commutative ops)
