+      if (Value *V = simplifyBinOp(Opcode, B, C, FMF, Q))
+        return V;
+      Value *NewBO = Builder.CreateBinOp(Opcode, B, C);
+      if (auto *NewBOI = dyn_cast<BinaryOperator>(NewBO))
+        NewBOI->copyIRFlags(&I);
+      return NewBO;
+    }
   } else if (LHSIsSelect && LHS->hasOneUse()) {
