I can see the code already handles this case! Look at lines 1146-1154:

```cpp
// (A ? B : C) op (A ? C : B) -> B op C (for commutative ops)
if (I.isCommutative() && B == F && C == E) {
    if (Value *V = simplifyBinOp(Opcode, B, C, FMF, Q))
        return V;
    Value *NewBO = Builder.CreateBinOp(Opcode, B, C);
    if (auto *NewBOI = dyn_cast<BinaryOperator>(NewBO))
